import jwt
import datetime
import hashlib
import base64

SECRET_KEY = 'your-secret-key'  # Replace with your secret key
ALGORITHM = 'HS256'  # Algorithm used for encoding and decoding the JWT token

def generate_jwt(user_id, role):
    payload = {
        'iat': datetime.datetime.utcnow(),  # Issued at: time when the token was issued
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),  # Expiration time
        'user_id': user_id,
        'role': role
    }

    encoded_payload = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return encoded_payload